class SafeErrorHandler:
    """
    Centralized error handler that prevents disclosure of sensitive
    internal details to clients while still logging full details server-side.
    """

    # Map of known error types to safe, generic client-facing messages
    SAFE_ERROR_MESSAGES = {
        "NotFoundError": "The requested resource was not found.",
        "ValidationError": "The request contains invalid data.",
        "PermissionError": "You do not have permission to perform this action.",
        "DatabaseError": "A data storage error occurred. Please try again later.",
        "ConnectionError": "A downstream service is unavailable. Please try again later.",
        "TimeoutError": "The operation timed out. Please try again later.",
    }

    # gRPC status code mapping for known error types
    STATUS_CODE_MAP = {
        "NotFoundError": grpc.StatusCode.NOT_FOUND,
        "ValidationError": grpc.StatusCode.INVALID_ARGUMENT,
        "PermissionError": grpc.StatusCode.PERMISSION_DENIED,
        "DatabaseError": grpc.StatusCode.INTERNAL,
        "ConnectionError": grpc.StatusCode.UNAVAILABLE,
        "TimeoutError": grpc.StatusCode.DEADLINE_EXCEEDED,
    }

    @classmethod
    def get_error_id(cls):
        """Generate a unique error ID for correlation between client and server logs."""
        import uuid
        return str(uuid.uuid4())[:12]

    @classmethod
    def handle_error(cls, context, exception, method_name, request_info=None):
        """
        Handle an exception safely:
        - Log full details (stack trace, internal state) server-side
        - Return only a safe, generic message to the client
        - Include an error correlation ID so support can look up details
        """
        error_id = cls.get_error_id()
        exception_type = type(exception).__name__

        # ---- SERVER-SIDE: Log everything for debugging ----
        full_details = {
            "error_id": error_id,
            "method": method_name,
            "exception_type": exception_type,
            "exception_message": str(exception),
            "stack_trace": traceback.format_exc(),
            "request_info": request_info,
        }

        logger.error(
            "gRPC error [%s] in %s: %s\nFull details: %s",
            error_id,
            method_name,
            str(exception),
            json.dumps(full_details, indent=2, default=str)
        )

        # ---- CLIENT-SIDE: Return only safe, generic information ----
        grpc_status = cls.STATUS_CODE_MAP.get(
            exception_type, grpc.StatusCode.INTERNAL
        )

        # Use a generic safe message; never expose stack traces, internal
        # state, database details, file paths, etc.
        safe_message = cls.SAFE_ERROR_MESSAGES.get(
            exception_type,
            "An internal error occurred. Please try again later."
        )

        # The only "detail" we give the client is the correlation ID
        # so they can report it to support for investigation.
        client_facing_details = json.dumps({
            "error_id": error_id,
            "message": safe_message,
        })

        context.set_code(grpc_status)
        context.set_details(client_facing_details)

        return error_id


