class SafeErrorInterceptor(grpc.ServerInterceptor):
    """
    Server interceptor that acts as a safety net to catch any unhandled
    exceptions that might leak through service methods.
    This ensures NO internal details ever reach the client.
    """

    def intercept_service(self, continuation, handler_call_details):
        """Intercept and wrap service handlers."""
        handler = continuation(handler_call_details)
        if handler is None:
            return handler

        if handler.unary_unary:
            return grpc.unary_unary_rpc_method_handler(
                self._wrap_handler(handler.unary_unary, handler_call_details.method),
                request_deserializer=handler.request_deserializer,
                response_serializer=handler.response_serializer,
            )

        # Return original handler for streaming RPCs (extend as needed)
        return handler

    def _wrap_handler(self, original_handler, method_name):
        """Wrap a handler to catch any unhandled exceptions."""

        def safe_handler(request, context):
            try:
                return original_handler(request, context)
            except Exception as e:
                # This is the last line of defense
                error_id = SafeErrorHandler.get_error_id()
                logger.critical(
                    "UNHANDLED exception escaped service method [%s] in %s: %s\n%s",
                    error_id, method_name, str(e), traceback.format_exc()
                )
                context.set_code(grpc.StatusCode.INTERNAL)
                context.set_details(json.dumps({
                    "error_id": error_id,
                    "message": "An internal error occurred. Please try again later.",
                }))
                return None

        return safe_handler


